function r(n,t){const e=n*t.downPaymentPercentage/100,s=n-e,o=s*t.processingFee/100,m=s*t.interestRate/100,a=e+s+m+o,i=t.installments===1?a:(s+m+o)/t.installments,c=12/t.installments,l=t.installments===1?a:i/c;return{propertyPrice:n,downPayment:e,loanAmount:s,installmentAmount:i,totalInstallments:t.installments,totalInterest:m,processingFee:o,totalAmount:a,monthlyPayment:l}}function u(n,t="AED"){return`${t} ${n.toLocaleString("en-US",{minimumFractionDigits:0,maximumFractionDigits:0})}`}export{r as c,u as f};
